mapper.select:
SELECT CAST(w.question_id AS CHAR) AS question_id, q.stem, CAST(s.id AS CHAR) AS subject_id, s.name AS subject_name, CAST(t.id AS CHAR) AS topic_id, t.name AS topic_name, w.wrong_count, CASE WHEN w.resolved = 1 THEN TRUE ELSE FALSE END AS resolved, REPLACE(CAST(w.last_wrong_at AS CHAR), ' ', 'T') AS last_wrong_at FROM wrong_book_item w INNER JOIN question q ON q.id = w.question_id INNER JOIN topic t ON t.id = w.topic_id INNER JOIN subject s ON s.id = w.subject_id WHERE w.user_id = #{userId} AND w.subject_id = #{subjectId}
AND w.topic_id = #{topicId}
AND w.resolved = 0
ORDER BY w.resolved ASC, w.last_wrong_at DESC, w.question_id ASC
